def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 6):
                pow_term = ratio ** (2 * k + 1)
                denom = (k * 3 - 1)
                penalty += pow_term / denom
            priorities[i] = ratio ** 4 + penalty + (ratio * 2.5)
            if ratio > 2:
                priorities[i] *= 1.5
                for x in range(1, 4):
                    priorities[i] += (np.sin(ratio * x) / (x+1))
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = (-1) ** (j + 1)
                term = sign * (np.cos(ratio * j) ** 2) / j
                score += term
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.7:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1) ** m) * (ratio ** m) / (m + 1)
                priorities[i] += abs(extra)
            if ratio > 0.9:
                extra2 = 0
                for p in range(1, 3):
                    for q in range(1, 4):
                        extra2 += (np.tan(ratio / (p + q + 1))) / ((p+q) * 2)
                priorities[i] += abs(extra2)
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and priorities[i] > 50:
            reduction = 0
            for z in range(1, 6):
                reduction += np.log1p(priorities[i]) / (z * 10)
            priorities[i] -= reduction
            if priorities[i] < 0:
                priorities[i] = 0
    return priorities
